package com.ai.hotspot.data.mapper

import com.ai.hotspot.data.local.entity.HotspotEntity
import com.ai.hotspot.domain.model.Category
import com.ai.hotspot.domain.model.Hotspot
import com.ai.hotspot.domain.model.Source
import kotlinx.serialization.encodeToString
import kotlinx.serialization.json.Json
import java.time.LocalDateTime
import java.time.ZoneOffset

/**
 * 数据映射器 - Domain Model <-> Entity
 */
object HotspotMapper {

    private val json = Json { ignoreUnknownKeys = true }

    fun Hotspot.toEntity(): HotspotEntity {
        return HotspotEntity(
            id = id,
            title = title,
            description = description,
            source = source.name,
            category = category.name,
            url = url,
            stars = stars,
            author = author,
            tags = json.encodeToString(tags),
            imageUrl = imageUrl,
            publishedAt = publishedAt.toEpochSecond(ZoneOffset.UTC),
            fetchedAt = fetchedAt.toEpochSecond(ZoneOffset.UTC),
            isRead = isRead,
            isBookmarked = isBookmarked
        )
    }

    fun HotspotEntity.toDomain(): Hotspot {
        return Hotspot(
            id = id,
            title = title,
            description = description,
            source = Source.valueOf(source),
            category = Category.valueOf(category),
            url = url,
            stars = stars,
            author = author,
            tags = try {
                json.decodeFromString(tags)
            } catch (e: Exception) {
                emptyList()
            },
            imageUrl = imageUrl,
            publishedAt = LocalDateTime.ofEpochSecond(publishedAt, 0, ZoneOffset.UTC),
            fetchedAt = LocalDateTime.ofEpochSecond(fetchedAt, 0, ZoneOffset.UTC),
            isRead = isRead,
            isBookmarked = isBookmarked
        )
    }

    fun List<HotspotEntity>.toDomainList(): List<Hotspot> {
        return map { it.toDomain() }
    }

    fun List<Hotspot>.toEntityList(): List<HotspotEntity> {
        return map { it.toEntity() }
    }
}

package com.ai.hotspot.data.local.dao

import androidx.room.*
import com.ai.hotspot.data.local.entity.HotspotEntity
import kotlinx.coroutines.flow.Flow

@Dao
interface HotspotDao {

    @Query("SELECT * FROM hotspots ORDER BY publishedAt DESC")
    fun getAllHotspots(): Flow<List<HotspotEntity>>

    @Query("SELECT * FROM hotspots WHERE source IN (:sources) ORDER BY publishedAt DESC")
    fun getBySources(sources: List<String>): Flow<List<HotspotEntity>>

    @Query("SELECT * FROM hotspots WHERE category IN (:categories) ORDER BY publishedAt DESC")
    fun getByCategories(categories: List<String>): Flow<List<HotspotEntity>>

    @Query("SELECT * FROM hotspots WHERE isBookmarked = 1 ORDER BY publishedAt DESC")
    fun getBookmarked(): Flow<List<HotspotEntity>>

    @Query("SELECT * FROM hotspots WHERE isRead = 0 ORDER BY publishedAt DESC")
    fun getUnread(): Flow<List<HotspotEntity>>

    @Query("""
        SELECT * FROM hotspots
        WHERE title LIKE '%' || :query || '%'
           OR description LIKE '%' || :query || '%'
           OR tags LIKE '%' || :query || '%'
        ORDER BY publishedAt DESC
    """)
    fun search(query: String): Flow<List<HotspotEntity>>

    @Query("SELECT * FROM hotspots WHERE id = :id")
    suspend fun getById(id: String): HotspotEntity?

    @Query("SELECT * FROM hotspots WHERE url = :url LIMIT 1")
    suspend fun getByUrl(url: String): HotspotEntity?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insert(hotspot: HotspotEntity)

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertAll(hotspots: List<HotspotEntity>)

    @Update
    suspend fun update(hotspot: HotspotEntity)

    @Query("UPDATE hotspots SET isRead = 1 WHERE id = :id")
    suspend fun markAsRead(id: String)

    @Query("UPDATE hotspots SET isBookmarked = :bookmarked WHERE id = :id")
    suspend fun setBookmarked(id: String, bookmarked: Boolean)

    @Query("DELETE FROM hotspots WHERE fetchedAt < :timestamp")
    suspend fun deleteOlderThan(timestamp: Long)

    @Query("DELETE FROM hotspots")
    suspend fun deleteAll()

    @Query("SELECT COUNT(*) FROM hotspots")
    suspend fun getCount(): Int

    @Query("SELECT MAX(fetchedAt) FROM hotspots")
    suspend fun getLastFetchTime(): Long?
}

