package com.ai.hotspot.presentation.home

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.ai.hotspot.domain.model.Category
import com.ai.hotspot.domain.model.FilterState
import com.ai.hotspot.domain.model.Source
import com.ai.hotspot.domain.usecase.GetHotspotsUseCase
import com.ai.hotspot.domain.usecase.HotspotActionsUseCase
import com.ai.hotspot.domain.usecase.RefreshHotspotsUseCase
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.catch
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

@HiltViewModel
class HomeViewModel @Inject constructor(
    private val getHotspotsUseCase: GetHotspotsUseCase,
    private val refreshHotspotsUseCase: RefreshHotspotsUseCase,
    private val hotspotActionsUseCase: HotspotActionsUseCase
) : ViewModel() {

    private val _state = MutableStateFlow(HomeState())
    val state = _state.asStateFlow()

    init {
        loadHotspots()
    }

    private fun loadHotspots() {
        viewModelScope.launch {
            _state.update { it.copy(isLoading = true) }

            getHotspotsUseCase(_state.value.filterState)
                .catch { e ->
                    _state.update {
                        it.copy(
                            error = e.message,
                            isLoading = false
                        )
                    }
                }
                .collect { hotspots ->
                    _state.update {
                        it.copy(
                            hotspots = hotspots,
                            isLoading = false,
                            error = null
                        )
                    }
                }
        }
    }

    fun refresh() {
        viewModelScope.launch {
            _state.update { it.copy(isRefreshing = true) }

            refreshHotspotsUseCase()
                .onSuccess {
                    _state.update { it.copy(isRefreshing = false, error = null) }
                }
                .onFailure { e ->
                    _state.update {
                        it.copy(
                            isRefreshing = false,
                            error = e.message
                        )
                    }
                }
        }
    }

    fun toggleBookmark(hotspotId: String, isCurrentlyBookmarked: Boolean) {
        viewModelScope.launch {
            hotspotActionsUseCase.toggleBookmark(hotspotId, isCurrentlyBookmarked)
        }
    }

    fun markAsRead(hotspotId: String) {
        viewModelScope.launch {
            hotspotActionsUseCase.markAsRead(hotspotId)
        }
    }

    fun updateFilter(filterState: FilterState) {
        _state.update { it.copy(filterState = filterState) }
        loadHotspots()
    }

    fun toggleFilterSheet() {
        _state.update { it.copy(showFilterSheet = !it.showFilterSheet) }
    }

    fun toggleSearchBar() {
        _state.update {
            it.copy(
                showSearchBar = !it.showSearchBar,
                searchQuery = if (it.showSearchBar) "" else it.searchQuery
            )
        }
    }

    fun updateSearchQuery(query: String) {
        _state.update {
            it.copy(
                searchQuery = query,
                filterState = it.filterState.copy(searchQuery = query)
            )
        }
        loadHotspots()
    }

    fun clearError() {
        _state.update { it.copy(error = null) }
    }
}

package com.ai.hotspot.presentation.detail

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.ai.hotspot.domain.model.Hotspot
import com.ai.hotspot.domain.usecase.HotspotActionsUseCase
import com.ai.hotspot.domain.repository.IHotspotRepository
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

data class DetailState(
    val hotspot: Hotspot? = null,
    val isLoading: Boolean = false,
    val error: String? = null
)

@HiltViewModel
class DetailViewModel @Inject constructor(
    private val repository: IHotspotRepository,
    private val actionsUseCase: HotspotActionsUseCase
) : ViewModel() {

    private val _state = MutableStateFlow(DetailState())
    val state = _state.asStateFlow()

    fun loadHotspot(id: String) {
        viewModelScope.launch {
            _state.update { it.copy(isLoading = true) }

            val hotspot = repository.getHotspotById(id)

            _state.update {
                it.copy(
                    hotspot = hotspot,
                    isLoading = false,
                    error = if (hotspot == null) "内容不存在" else null
                )
            }

            // 标记为已读
            hotspot?.let {
                repository.markAsRead(it.id)
            }
        }
    }

    fun toggleBookmark() {
        val hotspot = _state.value.hotspot ?: return

        viewModelScope.launch {
            actionsUseCase.toggleBookmark(hotspot.id, hotspot.isBookmarked)

            _state.update {
                it.copy(
                    hotspot = it.hotspot?.copy(isBookmarked = !hotspot.isBookmarked)
                )
            }
        }
    }
}

package com.ai.hotspot.presentation.detail

import android.content.Intent
import android.net.Uri
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.foundation.verticalScroll
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.automirrored.filled.ArrowBack
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import com.ai.hotspot.domain.model.Hotspot
import com.ai.hotspot.presentation.components.CategoryChip
import com.ai.hotspot.presentation.components.SourceChip
import com.ai.hotspot.presentation.components.formatRelativeTime
import com.ai.hotspot.presentation.components.formatStars
import com.ai.hotspot.presentation.theme.GoldLeaf

@Composable
fun DetailScreen(
    hotspotId: String,
    viewModel: DetailViewModel = hiltViewModel(),
    onBackClick: () -> Unit
) {
    val state by viewModel.state.collectAsState()
    val context = LocalContext.current

    LaunchedEffect(hotspotId) {
        viewModel.loadHotspot(hotspotId)
    }

    val hotspot = state.hotspot

    if (state.isLoading) {
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.Center
        ) {
            CircularProgressIndicator()
        }
        return
    }

    if (hotspot == null) {
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.Center
        ) {
            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                Text("内容不存在", style = MaterialTheme.typography.titleMedium)
                Spacer(modifier = Modifier.height(16.dp))
                Button(onClick = onBackClick) {
                    Text("返回")
                }
            }
        }
        return
    }

    Scaffold(
        topBar = {
            DetailTopBar(
                onBackClick = onBackClick,
                onShareClick = {
                    // 分享
                    val shareIntent = Intent(Intent.ACTION_SEND).apply {
                        type = "text/plain"
                        putExtra(Intent.EXTRA_SUBJECT, hotspot.title)
                        putExtra(Intent.EXTRA_TEXT, "${hotspot.title}\n\n${hotspot.description}\n\n${hotspot.url}")
                    }
                    context.startActivity(Intent.createChooser(shareIntent, "分享到"))
                },
                onBookmarkClick = {
                    viewModel.toggleBookmark()
                },
                isBookmarked = hotspot.isBookmarked
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .verticalScroll(rememberScrollState())
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(16.dp)
        ) {
            // 来源和时间
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                SourceChip(source = hotspot.source)
                Text(
                    text = formatRelativeTime(hotspot.publishedAt),
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }

            // 标题
            Text(
                text = hotspot.title,
                style = MaterialTheme.typography.headlineMedium,
                color = MaterialTheme.colorScheme.onBackground
            )

            // 元信息
            Row(
                horizontalArrangement = Arrangement.spacedBy(16.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                CategoryChip(category = hotspot.category)

                if (hotspot.stars != null && hotspot.stars > 0) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(
                            imageVector = Icons.Default.Star,
                            contentDescription = "Stars",
                            tint = GoldLeaf,
                            modifier = Modifier.size(18.dp)
                        )
                        Spacer(modifier = Modifier.width(4.dp))
                        Text(
                            text = formatStars(hotspot.stars),
                            style = MaterialTheme.typography.bodyMedium
                        )
                    }
                }

                if (hotspot.author != null) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(
                            imageVector = Icons.Default.Person,
                            contentDescription = "Author",
                            modifier = Modifier.size(18.dp),
                            tint = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                        Spacer(modifier = Modifier.width(4.dp))
                        Text(
                            text = hotspot.author,
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            }

            Divider(color = MaterialTheme.colorScheme.outlineVariant)

            // 描述内容
            if (hotspot.description.isNotEmpty()) {
                Text(
                    text = hotspot.description,
                    style = MaterialTheme.typography.bodyLarge,
                    color = MaterialTheme.colorScheme.onBackground,
                    modifier = Modifier.padding(vertical = 8.dp)
                )
            }

            // 标签
            if (hotspot.tags.isNotEmpty()) {
                WrapRow(
                    horizontalGap = 8.dp
                ) {
                    hotspot.tags.forEach { tag ->
                        SuggestionChip(
                            onClick = { },
                            label = { Text(tag) },
                            modifier = Modifier.padding(bottom = 8.dp)
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(16.dp))

            // 打开原文按钮
            FilledTonalButton(
                onClick = {
                    val intent = Intent(Intent.ACTION_VIEW, Uri.parse(hotspot.url))
                    context.startActivity(intent)
                },
                modifier = Modifier.fillMaxWidth(),
                shape = RoundedCornerShape(12.dp)
            ) {
                Icon(
                    imageVector = Icons.Default.OpenInNew,
                    contentDescription = null,
                    modifier = Modifier.size(18.dp)
                )
                Spacer(modifier = Modifier.width(8.dp))
                Text("查看原文")
            }
        }
    }
}

@OptIn(ExperimentalMaterial3Api::class)
