package com.ai.hotspot.presentation.settings

import androidx.compose.foundation.layout.*
import androidx.compose.foundation.rememberScrollState
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.foundation.text.KeyboardOptions
import androidx.compose.foundation.verticalScroll
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.automirrored.filled.ArrowBack
import androidx.compose.material.icons.filled.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.text.input.KeyboardType
import androidx.compose.ui.text.input.PasswordVisualTransformation
import androidx.compose.ui.text.input.VisualTransformation
import androidx.compose.ui.unit.dp
import androidx.hilt.navigation.compose.hiltViewModel
import com.ai.hotspot.domain.model.LLMConfig
import com.ai.hotspot.domain.model.LLMProvider
import com.ai.hotspot.presentation.theme.AppTheme
import com.ai.hotspot.presentation.theme.CeladonPrimary
import com.ai.hotspot.presentation.theme.rememberAppTheme

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SettingsScreen(
    viewModel: SettingsViewModel = hiltViewModel(),
    onBackClick: () -> Unit
) {
    val (currentTheme, setTheme) = rememberAppTheme()
    val state by viewModel.state.collectAsState()

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("设置") },
                navigationIcon = {
                    IconButton(onClick = onBackClick) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "返回")
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = MaterialTheme.colorScheme.background
                )
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .verticalScroll(rememberScrollState())
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(24.dp)
        ) {
            // ========== 1. 主题设置 ==========
            SectionTitle("主题")
            AppTheme.entries.forEach { theme ->
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(theme.displayName, style = MaterialTheme.typography.bodyLarge)
                    RadioButton(
                        selected = currentTheme == theme,
                        onClick = { setTheme(theme) }
                    )
                }
            }

            HorizontalDivider()

            // ========== 2. 关键词设置 ==========
            SectionTitle("抓取关键词")
            Text(
                "多个关键词用逗号分隔，抓取时只保留匹配的内容",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )
            OutlinedTextField(
                value = state.keywords,
                onValueChange = { viewModel.updateKeywords(it) },
                modifier = Modifier.fillMaxWidth(),
                placeholder = { Text("如：AI,大模型,LLM,GPT") },
                singleLine = false,
                maxLines = 3
            )

            HorizontalDivider()

            // ========== 3. 订阅源管理 ==========
            SectionTitle("订阅源管理")

            // 添加新源
            var newRssUrl by remember { mutableStateOf("") }
            var newRssName by remember { mutableStateOf("") }

            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp),
                verticalAlignment = Alignment.Top
            ) {
                Column(modifier = Modifier.weight(1f)) {
                    OutlinedTextField(
                        value = newRssName,
                        onValueChange = { newRssName = it },
                        modifier = Modifier.fillMaxWidth(),
                        placeholder = { Text("源名称") },
                        singleLine = true
                    )
                    Spacer(modifier = Modifier.height(8.dp))
                    OutlinedTextField(
                        value = newRssUrl,
                        onValueChange = { newRssUrl = it },
                        modifier = Modifier.fillMaxWidth(),
                        placeholder = { Text("RSS 链接") },
                        singleLine = true,
                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Uri)
                    )
                }
                FilledIconButton(
                    onClick = {
                        if (newRssUrl.isNotBlank() && newRssName.isNotBlank()) {
                            viewModel.addRssSource(newRssUrl.trim(), newRssName.trim())
                            newRssUrl = ""
                            newRssName = ""
                        }
                    },
                    modifier = Modifier.padding(top = 8.dp)
                ) {
                    Icon(Icons.Default.Add, contentDescription = "添加")
                }
            }

            // 已有自定义源列表
            state.customRssSources.forEach { rss ->
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(8.dp)
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(12.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column(modifier = Modifier.weight(1f)) {
                            Text(rss.name, style = MaterialTheme.typography.bodyMedium)
                            Text(
                                rss.url,
                                style = MaterialTheme.typography.bodySmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant,
                                maxLines = 1
                            )
                        }
                        IconButton(onClick = { viewModel.deleteRssSource(rss.id) }) {
                            Icon(
                                Icons.Default.Delete,
                                contentDescription = "删除",
                                tint = MaterialTheme.colorScheme.error
                            )
                        }
                    }
                }
            }

            HorizontalDivider()

            // ========== 4. 大模型配置 ==========
            SectionTitle("大模型配置")
            Text(
                "配置后可用于内容翻译和智能摘要（开发中）",
                style = MaterialTheme.typography.bodySmall,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )

            // 提供商选择
            Text("选择提供商", style = MaterialTheme.typography.labelLarge)
            Column {
                LLMProvider.domesticProviders.forEach { provider ->
                    ProviderRow(provider, state.selectedProvider) {
                        viewModel.selectProvider(it)
                    }
                }
                Spacer(modifier = Modifier.height(4.dp))
                LLMProvider.internationalProviders.forEach { provider ->
                    ProviderRow(provider, state.selectedProvider) {
                        viewModel.selectProvider(it)
                    }
                }
            }

            // API Key
            var showApiKey by remember { mutableStateOf(false) }
            OutlinedTextField(
                value = state.apiKey,
                onValueChange = { viewModel.updateApiKey(it) },
                modifier = Modifier.fillMaxWidth(),
                label = { Text("API Key") },
                singleLine = true,
                visualTransformation = if (showApiKey) VisualTransformation.None else PasswordVisualTransformation(),
                trailingIcon = {
                    IconButton(onClick = { showApiKey = !showApiKey }) {
                        Icon(
                            if (showApiKey) Icons.Default.VisibilityOff else Icons.Default.Visibility,
                            contentDescription = if (showApiKey) "隐藏" else "显示"
                        )
                    }
                }
            )

            // 模型选择
            val models = LLMConfig.displayModels[state.selectedProvider] ?: emptyList()
            if (models.isNotEmpty()) {
                Text("选择模型", style = MaterialTheme.typography.labelLarge)
                models.forEach { model ->
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(model, style = MaterialTheme.typography.bodyMedium)
                        RadioButton(
                            selected = state.selectedModel == model,
                            onClick = { viewModel.selectModel(model) }
                        )
                    }
                }
            }

            Spacer(modifier = Modifier.height(32.dp))
        }
    }
}

@Composable
private fun SectionTitle(title: String) {
    Text(
        text = title,
        style = MaterialTheme.typography.titleMedium,
        color = CeladonPrimary
    )
}

@Composable
private fun ProviderRow(
    provider: LLMProvider,
    selected: LLMProvider,
    onSelect: (LLMProvider) -> Unit
) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Text(provider.displayName, style = MaterialTheme.typography.bodyMedium)
        RadioButton(
            selected = selected == provider,
            onClick = { onSelect(provider) }
        )
    }
}

package com.ai.hotspot.presentation.settings

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.ai.hotspot.data.local.UserPrefsManager
import com.ai.hotspot.data.local.entity.CustomRssEntity
import com.ai.hotspot.domain.model.LLMConfig
import com.ai.hotspot.domain.model.LLMProvider
import com.ai.hotspot.domain.repository.IHotspotRepository
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

data class SettingsState(
    val keywords: String = "",
    val customRssSources: List<CustomRssEntity> = emptyList(),
    val selectedProvider: LLMProvider = LLMProvider.DEEPSEEK,
    val apiKey: String = "",
    val selectedModel: String = ""
)

@HiltViewModel
class SettingsViewModel @Inject constructor(
    private val userPrefsManager: UserPrefsManager,
    private val repository: IHotspotRepository
) : ViewModel() {

    private val _state = MutableStateFlow(SettingsState())
    val state = _state.asStateFlow()

    init {
        loadPrefs()
        loadCustomRss()
    }

    private fun loadPrefs() {
        viewModelScope.launch {
            userPrefsManager.keywords.collect { kw ->
                _state.update { it.copy(keywords = kw) }
            }
        }
        viewModelScope.launch {
            userPrefsManager.llmProvider.collect { provider ->
                _state.update {
                    it.copy(
                        selectedProvider = provider,
                        selectedModel = it.selectedModel.ifEmpty {
                            LLMConfig.defaultModels[provider] ?: ""
                        }
                    )
                }
            }
        }
        viewModelScope.launch {
            userPrefsManager.llmApiKey.collect { key ->
                _state.update { it.copy(apiKey = key) }
            }
        }
        viewModelScope.launch {
            userPrefsManager.llmModel.collect { model ->
                if (model.isNotEmpty()) {
                    _state.update { it.copy(selectedModel = model) }
                }
            }
        }
    }

    private fun loadCustomRss() {
        viewModelScope.launch {
            repository.getCustomRssSources().collect { sources ->
                _state.update { it.copy(customRssSources = sources) }
            }
        }
    }

    fun updateKeywords(keywords: String) {
        _state.update { it.copy(keywords = keywords) }
        viewModelScope.launch { userPrefsManager.setKeywords(keywords) }
    }

    fun addRssSource(url: String, name: String) {
        viewModelScope.launch { repository.addCustomRssSource(url, name) }
    }

    fun deleteRssSource(id: Long) {
        viewModelScope.launch { repository.deleteCustomRssSource(id) }
    }

    fun selectProvider(provider: LLMProvider) {
        val defaultModel = LLMConfig.defaultModels[provider] ?: ""
        _state.update { it.copy(selectedProvider = provider, selectedModel = defaultModel) }
        viewModelScope.launch {
            userPrefsManager.setLlmProvider(provider)
            userPrefsManager.setLlmModel(defaultModel)
        }
    }

    fun updateApiKey(key: String) {
        _state.update { it.copy(apiKey = key) }
        viewModelScope.launch { userPrefsManager.setLlmApiKey(key) }
    }

    fun selectModel(model: String) {
        _state.update { it.copy(selectedModel = model) }
        viewModelScope.launch { userPrefsManager.setLlmModel(model) }
    }
}

